class InMemoryStore:
    """Simple in-memory store for users, tokens, etc."""

    def __init__(self):
        self.users = {}
        self.tokens = {}
        self.refresh_tokens = {}
        self._seed_data()

    def _seed_data(self):
        users_data = [
            {
                "user_id": "user-001",
                "username": "alice",
                "password_hash": hashlib.sha256("password123".encode()).hexdigest(),
                "email": "alice@example.com",
                "full_name": "Alice Johnson",
                "role": "admin",
                "is_active": True,
                "bio": "Platform architect and team lead.",
                "avatar_url": "https://avatars.example.com/alice.png",
                "metadata": {"department": "Engineering", "location": "NYC"},
                "created_at": 1700000000,
            },
            {
                "user_id": "user-002",
                "username": "bob",
                "password_hash": hashlib.sha256("securepass".encode()).hexdigest(),
                "email": "bob@example.com",
                "full_name": "Bob Smith",
                "role": "user",
                "is_active": True,
                "bio": "Backend developer.",
                "avatar_url": "https://avatars.example.com/bob.png",
                "metadata": {"department": "Engineering", "location": "SF"},
                "created_at": 1700100000,
            },
            {
                "user_id": "user-003",
                "username": "charlie",
                "password_hash": hashlib.sha256("charlie456".encode()).hexdigest(),
                "email": "charlie@example.com",
                "full_name": "Charlie Brown",
                "role": "user",
                "is_active": False,
                "bio": "Data analyst.",
                "avatar_url": "",
                "metadata": {"department": "Analytics", "location": "LA"},
                "created_at": 1700200000,
            },
        ]
        for u in users_data:
            self.users[u["username"]] = u

    def authenticate(self, username, password):
        user = self.users.get(username)
        if not user:
            return None, "User not found"
        if not user["is_active"]:
            return None, "Account is deactivated"
        pw_hash = hashlib.sha256(password.encode()).hexdigest()
        if pw_hash != user["password_hash"]:
            return None, "Invalid password"
        token = secrets.token_hex(32)
        refresh_token = secrets.token_hex(32)
        expires_at = int(time.time()) + 3600
        self.tokens[token] = {
            "user_id": user["user_id"],
            "username": user["username"],
            "expires_at": expires_at,
        }
        self.refresh_tokens[refresh_token] = {
            "user_id": user["user_id"],
            "username": user["username"],
        }
        return {
            "token": token,
            "refresh_token": refresh_token,
            "expires_at": expires_at,
        }, "Login successful"

    def validate_token(self, token):
        info = self.tokens.get(token)
        if not info:
            return None, "Token not found"
        if info["expires_at"] < int(time.time()):
            del self.tokens[token]
            return None, "Token expired"
        return info, "Token valid"

    def invalidate_token(self, token):
        if token in self.tokens:
            del self.tokens[token]
            return True
        return False

    def refresh(self, refresh_token):
        info = self.refresh_tokens.get(refresh_token)
        if not info:
            return None, "Invalid refresh token"
        del self.refresh_tokens[refresh_token]
        new_token = secrets.token_hex(32)
        new_refresh = secrets.token_hex(32)
        expires_at = int(time.time()) + 3600
        self.tokens[new_token] = {
            "user_id": info["user_id"],
            "username": info["username"],
            "expires_at": expires_at,
        }
        self.refresh_tokens[new_refresh] = {
            "user_id": info["user_id"],
            "username": info["username"],
        }
        return {
            "token": new_token,
            "refresh_token": new_refresh,
            "expires_at": expires_at,
        }, "Token refreshed"

    def get_user_by_id(self, user_id):
        for u in self.users.values():
            if u["user_id"] == user_id:
                return u
        return None

    def list_users(self, page=1, page_size=10):
        all_users = list(self.users.values())
        start = (page - 1) * page_size
        end = start + page_size
        return all_users[start:end], len(all_users)

    def search_users(self, query, page=1, page_size=10):
        query_lower = query.lower()
        matched = [
            u for u in self.users.values()
            if query_lower in u["username"].lower()
            or query_lower in u["full_name"].lower()
            or query_lower in u["email"].lower()
        ]
        start = (page - 1) * page_size
        end = start + page_size
        return matched[start:end], len(matched)


