class AuthServiceServicer(microservices_pb2_grpc.AuthServiceServicer):
    """Implementation of the AuthService gRPC service."""

    def Login(self, request, context):
        if not request.username or not request.password:
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details("Username and password are required")
            return microservices_pb2.LoginResponse(
                success=False, message="Username and password are required"
            )

        result, message = store.authenticate(request.username, request.password)
        if result is None:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details(message)
            return microservices_pb2.LoginResponse(success=False, message=message)

        return microservices_pb2.LoginResponse(
            success=True,
            token=result["token"],
            refresh_token=result["refresh_token"],
            message=message,
            expires_at=result["expires_at"],
        )

    def ValidateToken(self, request, context):
        if not request.token:
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details("Token is required")
            return microservices_pb2.TokenResponse(valid=False, message="Token is required")

        info, message = store.validate_token(request.token)
        if info is None:
            return microservices_pb2.TokenResponse(valid=False, message=message)

        return microservices_pb2.TokenResponse(
            valid=True,
            user_id=info["user_id"],
            username=info["username"],
            message=message,
        )

    def Logout(self, request, context):
        if not request.token:
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details("Token is required")
            return microservices_pb2.LogoutResponse(success=False, message="Token is required")

        success = store.invalidate_token(request.token)
        return microservices_pb2.LogoutResponse(
            success=success,
            message="Logged out successfully" if success else "Token not found",
        )

    def RefreshToken(self, request, context):
        if not request.refresh_token:
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details("Refresh token is required")
            return microservices_pb2.LoginResponse(
                success=False, message="Refresh token is required"
            )

        result, message = store.refresh(request.refresh_token)
        if result is None:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details(message)
            return microservices_pb2.LoginResponse(success=False, message=message)

        return microservices_pb2.LoginResponse(
            success=True,
            token=result["token"],
            refresh_token=result["refresh_token"],
            message=message,
            expires_at=result["expires_at"],
        )


class DataServiceServicer(microservices_pb2_grpc.DataServiceServicer):
    """Implementation of the DataService gRPC service."""

    def _check_auth(self, context):
        """Extract and validate token from metadata."""
        metadata = dict(context.invocation_metadata())
        token = metadata.get("authorization", "")
        if token.startswith("Bearer "):
            token = token[7:]
        if not token:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Authentication token required")
            return None
        info, message = store.validate_token(token)
        if info is None:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details(message)
            return None
        return info

    def GetUser(self, request, context):
        auth_info = self._check_auth(context)
        if auth_info is None:
            return microservices_pb2.UserResponse()

        user = store.get_user_by_id(request.user_id)
        if user is None:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(f"User {request.user_id} not found")
            return microservices_pb2.UserResponse()

        return microservices_pb2.UserResponse(
            user_id=user["user_id"],
            username=user["username"],
            email=user["email"],
            full_name=user["full_name"],
            role=user["role"],
            is_active=user["is_active"],
            created_at=user["created_at"],
        )

    def ListUsers(self, request, context):
        auth_info = self._check_auth(context)
        if auth_info is None:
            return microservices_pb2.ListUsersResponse()

        page = max(request.page, 1)
        page_size = min(max(request.page_size, 1), 100)

        users, total = store.list_users(page, page_size)
        user_responses = [
            microservices_pb2.UserResponse(
                user_id=u["user_id"],
                username=u["username"],
                email=u["email"],
                full_name=u["full_name"],
                role=u["role"],
                is_active=u["is_active"],
                created_at=u["created_at"],
            )
            for u in users
        ]

        return microservices_pb2.ListUsersResponse(
            users=user_responses,
            total_count=total,
            page=page,
            page_size=page_size,
        )

    def GetUserProfile(self, request, context):
        auth_info = self._check_auth(context)
        if auth_info is None:
            return microservices_pb2.UserProfileResponse()

        user = store.get_user_by_id(request.user_id)
        if user is None:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(f"User {request.user_id} not found")
            return microservices_pb2.UserProfileResponse()

        return microservices_pb2.UserProfileResponse(
            user_id=user["user_id"],
            username=user["username"],
            email=user["email"],
            full_name=user["full_name"],
            bio=user.get("bio", ""),
            avatar_url=user.get("avatar_url", ""),
            role=user["role"],
            metadata=user.get("metadata", {}),
        )

    def SearchUsers(self, request, context):
        auth_info = self._check_auth(context)
        if auth_info is None:
            return microservices_pb2.ListUsersResponse()

        if not request.query:
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details("Search query is required")
            return microservices_pb2.ListUsersResponse()

        page = max(request.page, 1)
        page_size = min(max(request.page_size, 1), 100)

        users, total = store.search_users(request.query, page, page_size)
        user_responses = [
            microservices_pb2.UserResponse(
                user_id=u["user_id"],
                username=u["username"],
                email=u["email"],
                full_name=u["full_name"],
                role=u["role"],
                is_active=u["is_active"],
                created_at=u["created_at"],
            )
            for u in users
        ]

        return microservices_pb2.ListUsersResponse(
            users=user_responses,
            total_count=total,
            page=page,
            page_size=page_size,
        )


