def serve(port=50051):
    """Start the gRPC server with TLS on the specified port."""
    # Load or generate TLS certificates
    ca_cert_pem, server_cert_pem, server_key_pem, _, _ = load_or_generate_certs()

    # Create server SSL credentials
    # For mutual TLS (mTLS), we pass the CA cert to verify client certificates.
    # require_client_auth=False for standard server-side TLS;
    # set to True for full mutual TLS.
    server_credentials = grpc.ssl_server_credentials(
        [(server_key_pem, server_cert_pem)],
        root_certificates=ca_cert_pem,
        require_client_auth=False,
    )

    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        options=[
            ("grpc.max_send_message_length", 50 * 1024 * 1024),
            ("grpc.max_receive_message_length", 50 * 1024 * 1024),
            ("grpc.keepalive_time_ms", 30000),
            ("grpc.keepalive_timeout_ms", 10000),
            ("grpc.keepalive_permit_without_calls", True),
        ],
    )

    microservices_pb2_grpc.add_AuthServiceServicer_to_server(AuthServiceServicer(), server)
    microservices_pb2_grpc.add_DataServiceServicer_to_server(DataServiceServicer(), server)

    # Bind with TLS — never use add_insecure_port in any environment
    bind_address = f"[::]:{port}"
    server.add_secure_port(bind_address, server_credentials)

    server.start()
    print(f"[SERVER] gRPC server started on port {port} with TLS")
    print(f"[SERVER] AuthService and DataService are ready to accept connections")
    print(f"[SERVER] TLS certificates located in: {os.path.join(os.path.dirname(os.path.abspath(__file__)), 'certs')}")

    return server


