class MicroservicesClient:
    """
    gRPC client that connects to the microservices server using TLS.
    Uses secure channel with TLS credentials instead of insecure_channel.
    """

    def __init__(self, host="localhost", port=50051, cert_dir=None):
        # Load TLS certificates
        ca_cert_pem, _, _, client_cert_pem, client_key_pem = load_or_generate_certs(cert_dir)

        # Create channel credentials using the CA cert to verify the server
        channel_credentials = grpc.ssl_channel_credentials(
            root_certificates=ca_cert_pem,
            private_key=client_key_pem,
            certificate_chain=client_cert_pem,
        )

        target = f"{host}:{port}"
        # Use secure_channel with TLS — never use insecure_channel
        self.channel = grpc.secure_channel(
            target,
            channel_credentials,
            options=[
                ("grpc.ssl_target_name_override", "localhost"),
                ("grpc.max_send_message_length", 50 * 1024 * 1024),
                ("grpc.max_receive_message_length", 50 * 1024 * 1024),
            ],
        )

        self.auth_stub = microservices_pb2_grpc.AuthServiceStub(self.channel)
        self.data_stub = microservices_pb2_grpc.DataServiceStub(self.channel)
        self._token = None
        self._refresh_token = None
        print(f"[CLIENT] Connected to {target} with TLS")

    def close(self):
        self.channel.close()

    def _auth_metadata(self):
        """Return metadata with authorization token."""
        if self._token:
            return [("authorization", f"Bearer {self._token}")]
        return []

    # --- Auth operations ---

    def login(self, username, password):
        request = microservices_pb2.LoginRequest(username=username, password=password)
        try:
            response = self.auth_stub.Login(request)
            if response.success:
                self._token = response.token
                self._refresh_token = response.refresh_token
            print(f"[CLIENT] Login: success={response.success}, message='{response.message}'")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] Login RPC error: {e.code()} - {e.details()}")
            return None

    def validate_token(self):
        if not self._token:
            print("[CLIENT] No token to validate")
            return None
        request = microservices_pb2.TokenRequest(token=self._token)
        try:
            response = self.auth_stub.ValidateToken(request)
            print(f"[CLIENT] ValidateToken: valid={response.valid}, user={response.username}, message='{response.message}'")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] ValidateToken RPC error: {e.code()} - {e.details()}")
            return None

    def refresh_token(self):
        if not self._refresh_token:
            print("[CLIENT] No refresh token available")
            return None
        request = microservices_pb2.RefreshTokenRequest(refresh_token=self._refresh_token)
        try:
            response = self.auth_stub.RefreshToken(request)
            if response.success:
                self._token = response.token
                self._refresh_token = response.refresh_token
            print(f"[CLIENT] RefreshToken: success={response.success}, message='{response.message}'")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] RefreshToken RPC error: {e.code()} - {e.details()}")
            return None

    def logout(self):
        if not self._token:
            print("[CLIENT] No token to logout")
            return None
        request = microservices_pb2.LogoutRequest(token=self._token)
        try:
            response = self.auth_stub.Logout(request)
            if response.success:
                self._token = None
                self._refresh_token = None
            print(f"[CLIENT] Logout: success={response.success}, message='{response.message}'")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] Logout RPC error: {e.code()} - {e.details()}")
            return None

    # --- Data operations ---

    def get_user(self, user_id):
        request = microservices_pb2.GetUserRequest(user_id=user_id)
        try:
            response = self.data_stub.GetUser(request, metadata=self._auth_metadata())
            print(f"[CLIENT] GetUser: id={response.user_id}, name={response.full_name}, role={response.role}")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] GetUser RPC error: {e.code()} - {e.details()}")
            return None

    def list_users(self, page=1, page_size=10):
        request = microservices_pb2.ListUsersRequest(page=page, page_size=page_size)
        try:
            response = self.data_stub.ListUsers(request, metadata=self._auth_metadata())
            print(f"[CLIENT] ListUsers: total={response.total_count}, page={response.page}, returned={len(response.users)}")
            for u in response.users:
                print(f"  - {u.user_id}: {u.username} ({u.full_name}) [active={u.is_active}]")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] ListUsers RPC error: {e.code()} - {e.details()}")
            return None

    def get_user_profile(self, user_id):
        request = microservices_pb2.GetUserProfileRequest(user_id=user_id)
        try:
            response = self.data_stub.GetUserProfile(request, metadata=self._auth_metadata())
            print(f"[CLIENT] GetUserProfile: {response.username} - {response.bio}")
            if response.metadata:
                print(f"  Metadata: {dict(response.metadata)}")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] GetUserProfile RPC error: {e.code()} - {e.details()}")
            return None

    def search_users(self, query, page=1, page_size=10):
        request = microservices_pb2.SearchUsersRequest(query=query, page=page, page_size=page_size)
        try:
            response = self.data_stub.SearchUsers(request, metadata=self._auth_metadata())
            print(f"[CLIENT] SearchUsers('{query}'): total={response.total_count}, returned={len(response.users)}")
            for u in response.users:
                print(f"  - {u.user_id}: {u.username} ({u.full_name})")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] SearchUsers RPC error: {e.code()} - {e.details()}")
            return None


