def run_client_demo():
    """Run a comprehensive client demo against the running server."""
    print("\n" + "=" * 60)
    print("  Microservices gRPC Client Demo (TLS)")
    print("=" * 60 + "\n")

    client = MicroservicesClient(host="localhost", port=50051)

    try:
        # 1. Login
        print("--- Step 1: Login ---")
        client.login("alice", "password123")
        print()

        # 2. Validate token
        print("--- Step 2: Validate Token ---")
        client.validate_token()
        print()

        # 3. List users
        print("--- Step 3: List Users ---")
        client.list_users(page=1, page_size=10)
        print()

        # 4. Get specific user
        print("--- Step 4: Get User ---")
        client.get_user("user-002")
        print()

        # 5. Get user profile
        print("--- Step 5: Get User Profile ---")
        client.get_user_profile("user-001")
        print()

        # 6. Search users
        print("--- Step 6: Search Users ---")
        client.search_users("bob")
        print()

        # 7. Refresh token
        print("--- Step 7: Refresh Token ---")
        client.refresh_token()
        print()

        # 8. Validate new token
        print("--- Step 8: Validate New Token ---")
        client.validate_token()
        print()

        # 9. Test failed login
        print("--- Step 9: Failed Login Attempt ---")
        bad_client = MicroservicesClient(host="localhost", port=50051)
        bad_client.login("alice", "wrongpassword")
        print()

        # 10. Test unauthenticated data access
        print("--- Step 10: Unauthenticated Data Access ---")
        bad_client.list_users()
        bad_client.close()
        print()

        # 11. Logout
        print("--- Step 11: Logout ---")
        client.logout()
        print()

        # 12. Try to access data after logout
        print("--- Step 12: Access After Logout ---")
        client.list_users()
        print()

    finally:
        client.close()

    print("=" * 60)
    print("  Demo Complete")
    print("=" * 60)


if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(description="Microservices gRPC Server/Client with TLS")
    parser.add_argument(
        "mode",
        choices=["server", "client", "both"],
        help="Run mode: 'server' to start the server, 'client' to run the demo client, 'both' to run server then client",
    )
    parser.add_argument("--port", type=int, default=50051, help="Port number (default: 50051)")
    args = parser.parse_args()

    if args.mode == "server":
        server = serve(port=args.port)
        try:
            print("[SERVER] Press Ctrl+C to stop")
            while True:
                time.sleep(86400)
        except KeyboardInterrupt:
            print("\n[SERVER] Shutting down...")
            server.stop(grace=5)

    elif args.mode == "client":
        run_client_demo()

    elif args.mode == "both":
        server = serve(port=args.port)
        time.sleep(1)  # Give server a moment to start
        try:
            run_client_demo()
        finally:
            print("\n[SERVER] Shutting down...")
            server.stop(grace=5)